import React from 'react';
import { useNavigate } from 'react-router-dom';

function Home() {
  const navigate = useNavigate();
  return (
    <div className="bg-gradient-to-br from-[#18181b] via-[#23232a] to-[#1e1b4b] min-h-screen text-white overflow-x-hidden">
      {/* Hero Section */}
      <section className="flex flex-col items-center justify-center pt-20 pb-12 animate-fade-in-up">
        <span className="mb-4 px-4 py-1 rounded-full bg-gradient-to-r from-purple-600 to-indigo-500 text-xs font-semibold shadow-lg animate-pulse">Powered by Cohere AI</span>
        <h1 className="text-5xl md:text-6xl font-extrabold text-center mb-4 bg-gradient-to-r from-fuchsia-500 via-purple-400 to-blue-500 bg-clip-text text-transparent animate-gradient-x">
          A Fast AI. <span className="bg-gradient-to-r from-purple-400 to-blue-500 bg-clip-text text-transparent">Scalable Code.</span>
        </h1>
        <p className="text-lg md:text-xl text-gray-300 text-center max-w-2xl mb-8 animate-fade-in">
          Our technology performing fast AI generation and it has guaranteed AI-based code generation. Proof of Quality, its algorithm enables unlimited speeds.
        </p>
        <div className="flex gap-4 mb-8">
          <button
            className="bg-gradient-to-r from-fuchsia-500 via-purple-500 to-blue-500 text-white px-6 py-2 rounded-lg font-semibold shadow-lg hover:scale-105 hover:shadow-lg hover:from-purple-600 hover:to-blue-600 transition duration-300"
            onClick={() => navigate('/generator')}
          >
            Get started
          </button>
          <button
            className="bg-[#23232a] text-white px-6 py-2 rounded-lg font-semibold border border-purple-700 hover:bg-purple-900/60 hover:border-fuchsia-500 transition duration-300"
            onClick={() => navigate('/docs')}
          >
            Documentation
          </button>
        </div>
        <div className="flex flex-wrap justify-center gap-6 mt-4">
          <div className="bg-[#23232a] rounded-xl p-6 min-w-[180px] text-center border border-purple-800 shadow-lg hover:scale-105 hover:border-fuchsia-500 transition duration-300 animate-fade-in-up" style={{animationDelay: '0.1s'}}>
            <div className="text-fuchsia-400 text-2xl font-bold animate-bounce">10M+</div>
            <div className="text-gray-400 text-sm">Lines Generated</div>
          </div>
          <div className="bg-[#23232a] rounded-xl p-6 min-w-[180px] text-center border border-purple-800 shadow-lg hover:scale-105 hover:border-fuchsia-500 transition duration-300 animate-fade-in-up" style={{animationDelay: '0.2s'}}>
            <div className="text-fuchsia-400 text-2xl font-bold animate-bounce">50K+</div>
            <div className="text-gray-400 text-sm">Developers</div>
          </div>
          <div className="bg-[#23232a] rounded-xl p-6 min-w-[180px] text-center border border-purple-800 shadow-lg hover:scale-105 hover:border-fuchsia-500 transition duration-300 animate-fade-in-up" style={{animationDelay: '0.3s'}}>
            <div className="text-fuchsia-400 text-2xl font-bold animate-bounce">25+</div>
            <div className="text-gray-400 text-sm">Languages</div>
          </div>
          <div className="bg-[#23232a] rounded-xl p-6 min-w-[180px] text-center border border-purple-800 shadow-lg hover:scale-105 hover:border-fuchsia-500 transition duration-300 animate-fade-in-up" style={{animationDelay: '0.4s'}}>
            <div className="text-fuchsia-400 text-2xl font-bold animate-bounce">99.5%</div>
            <div className="text-gray-400 text-sm">Success Rate</div>
          </div>
        </div>
      </section>

      {/* Features Section */}
      <section className="max-w-5xl mx-auto py-12 animate-fade-in-up">
        <h2 className="text-3xl md:text-4xl font-extrabold text-center mb-4 bg-gradient-to-r from-fuchsia-400 to-blue-500 bg-clip-text text-transparent animate-gradient-x">
          Why Choose <span className="bg-gradient-to-r from-purple-400 to-blue-500 bg-clip-text text-transparent">CodeGen AI?</span>
        </h2>
        <p className="text-center text-gray-300 mb-10 animate-fade-in">
          Experience the future of code generation with Cohere's cutting-edge AI technology
        </p>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="bg-[#23232a] rounded-xl p-6 border border-purple-800 shadow-lg hover:scale-105 hover:border-fuchsia-500 transition duration-300 animate-fade-in-up" style={{animationDelay: '0.1s'}}>
            <div className="text-fuchsia-400 font-bold mb-2">&lt;/&gt; Smart Code Generation</div>
            <div className="text-gray-300">Generate clean, production-ready code in multiple programming languages with Cohere's advanced AI models.</div>
          </div>
          <div className="bg-[#23232a] rounded-xl p-6 border border-purple-800 shadow-lg hover:scale-105 hover:border-fuchsia-500 transition duration-300 animate-fade-in-up" style={{animationDelay: '0.2s'}}>
            <div className="text-fuchsia-400 font-bold mb-2">⚡ Lightning Fast</div>
            <div className="text-gray-300">Get your code generated in seconds, not hours. Optimized for speed and efficiency.</div>
          </div>
          <div className="bg-[#23232a] rounded-xl p-6 border border-purple-800 shadow-lg hover:scale-105 hover:border-fuchsia-500 transition duration-300 animate-fade-in-up" style={{animationDelay: '0.3s'}}>
            <div className="text-fuchsia-400 font-bold mb-2">🛡️ Secure & Private</div>
            <div className="text-gray-300">Your code and data are protected with enterprise-grade security and privacy measures.</div>
          </div>
          <div className="bg-[#23232a] rounded-xl p-6 border border-purple-800 shadow-lg hover:scale-105 hover:border-fuchsia-500 transition duration-300 animate-fade-in-up" style={{animationDelay: '0.4s'}}>
            <div className="text-fuchsia-400 font-bold mb-2">🎯 Customizable Output</div>
            <div className="text-gray-300">Tailor the generated code to match your coding style and project requirements.</div>
          </div>
        </div>
      </section>

      {/* Call to Action Section */}
      <section className="flex flex-col items-center justify-center py-16 animate-fade-in-up">
        <h2 className="text-3xl md:text-4xl font-extrabold text-center mb-4 bg-gradient-to-r from-fuchsia-400 to-blue-500 bg-clip-text text-transparent animate-gradient-x">
          Ready to Generate Your <span className="bg-gradient-to-r from-purple-400 to-blue-500 bg-clip-text text-transparent">First Code?</span>
        </h2>
        <p className="text-center text-gray-300 mb-6 max-w-xl animate-fade-in">
          Join thousands of developers who are already using CodeGen AI to accelerate their development workflow.
        </p>
        <button
          className="bg-gradient-to-r from-fuchsia-500 via-purple-500 to-blue-500 text-white px-8 py-3 rounded-lg font-semibold shadow-lg hover:scale-110 hover:shadow-lg hover:from-purple-600 hover:to-blue-600 transition duration-300 text-lg"
          onClick={() => navigate('/generator')}
        >
          Get Started Now
        </button>
      </section>

      {/* Animations (Tailwind custom classes) */}
      <style>{`
        .animate-fade-in-up {
          animation: fadeInUp 1s cubic-bezier(0.4, 0, 0.2, 1) both;
        }
        .animate-fade-in {
          animation: fadeIn 1.2s cubic-bezier(0.4, 0, 0.2, 1) both;
        }
        .animate-gradient-x {
          background-size: 200% 200%;
          animation: gradientX 3s ease-in-out infinite;
        }
        @keyframes fadeInUp {
          from { opacity: 0; transform: translateY(40px); }
          to { opacity: 1; transform: translateY(0); }
        }
        @keyframes fadeIn {
          from { opacity: 0; }
          to { opacity: 1; }
        }
        @keyframes gradientX {
          0%, 100% { background-position: left center; }
          50% { background-position: right center; }
        }
      `}</style>
    </div>
  );
}

export default Home;
